scwin.onpageload = function () {
  scwin.vCoCd = $c.ses.getCoCd() || "";
  scwin.vCoClsCd = $c.ses.getCoClsCd() || "";
  scwin.vUserHomeClsCd = $c.ses.getUserHomeClsCd() || "";
  scwin.g_sCurrDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
  scwin.ADJM_MTHDCD_PREPAY = $c.data.getConstant($p, "ADJM_MTHDCD_PREPAY") || "";
  scwin.ADJM_MTHDCD_SUSPAY = $c.data.getConstant($p, "ADJM_MTHDCD_SUSPAY") || "";
  scwin.ADJM_MTHDCD_NOPAY = $c.data.getConstant($p, "ADJM_MTHDCD_NOPAY") || "";
  scwin.ADJM_MTHDCD_LONG_NOPAY = $c.data.getConstant($p, "ADJM_MTHDCD_LONG_NOPAY") || "";
  scwin.ADJM_MTHDCD_LONG_NOPAY_LEASE = $c.data.getConstant($p, "ADJM_MTHDCD_LONG_NOPAY_LEASE") || "";
  scwin.NO_DEDUCT_CLS_CD = $c.data.getConstant($p, "NO_DEDUCT_CLS_CD") || "";
  scwin.CO_CLS_CD_DONGBU = $c.data.getConstant($p, "CO_CLS_CD_DONGBU") || "";
  scwin.SUBSIDIARY_USER_HOME_CLS_CD = $c.data.getConstant($p, "SUBSIDIARY_USER_HOME_CLS_CD") || "";
  scwin.EVID_CLSCD_COR_CARD = $c.data.getConstant($p, "EVID_CLSCD_COR_CARD") || "";
  scwin.EVID_CLSCD_PRSN_CARD = $c.data.getConstant($p, "EVID_CLSCD_PRSN_CARD") || "";
  scwin.KOREA_WON = $c.data.getConstant($p, "KOREA_WON") || "KRW";
  scwin.DG_TRUE = 1;
  scwin.f_OnLoad();
};
scwin.onUdcCompleted = function () {};
scwin.f_OnLoad = async function () {
  $c.gus.cfTurnCreateFlag($p, true);
  $c.gus.cfDisableKey($p);
  ds_evidence.removeAll();
  ds_evidence.insertRow(0);
  await $c.sbm.execute($p, sbm_evidClsCd);
  await $c.sbm.execute($p, sbm_asetPattern);
  scwin.f_AddAset();
  scwin.f_AddAdjustment();
  scwin.f_Add();
  $c.gus.cfTurnCreateFlag($p, false);
  lc_evidClsCd.setFocus();
  lc_payCrcCd.setValue(scwin.KOREA_WON);
  $c.gus.cfDisableObjects($p, [ed_payAmtFcrc]);
  lc_acqCls.setSelectedIndex(0);
  ds_evidence.setCellData(0, "evidFileClsCd", "00");
};
scwin.dataSetDebug = function (dataList, isDebug) {
  if (isDebug == true) {
    let str = "[[[[" + dataList.id + "]]]]]\n";
    let colInfos = dataList.getColumnInfo();
    for (let dsRow = 0; dsRow < dataList.getRowCount(); dsRow++) {
      for (let dsCol = 0; dsCol < colInfos.length; dsCol++) {
        let colId = colInfos[dsCol].id;
        str += "[" + colId + "] " + dataList.getCellData(dsRow, colId) + ", ";
      }
      str += "\n\n";
    }
    alert(str);
  }
};
scwin.btn_save_onclick = function (e) {
  scwin.f_Save();
};
scwin.f_Save = async function () {
  scwin.f_SaveProc();
};
scwin.f_SaveProc = async function () {
  let evidFileClsCd = ds_evidence.getCellData(0, "evidFileClsCd");
  if (fileUploadGDS.getRowCount() > 0) {
    if (evidFileClsCd == "" || evidFileClsCd == "00") {
      await $c.win.alert($p, "증빙파일구분을 선택하세요");
      return;
    }
  }
  for (let i = 0; i < ds_adjustment.getRowCount(); i++) {
    if (lc_payCrcCd.getValue() != scwin.KOREA_WON) {
      let changeExchRt = ds_adjustment.getCellData(i, "exchRt");
      dma_exchRtSearch.set("crcCd", ds_adjustment.getCellData(i, "payCrcCd"));
      dma_exchRtSearch.set("stdDt", ed_acqDt.getValue());
      await $c.sbm.execute($p, sbm_exchRt);
      scwin.checkExchRt = ds_exchRt.getCellData(ds_exchRt.getRowPosition(), "stdExchRt");
      if (changeExchRt < scwin.checkExchRt * 0.9 || changeExchRt > scwin.checkExchRt * 1.1) {
        await $c.win.alert($p, '통화코드 선택시 환율 금액 : ' + scwin.checkExchRt + '원' + '\n' + '환율의 90%  가 되는 금액  : ' + Math.round(scwin.checkExchRt * 0.9 * 100) / 100.00 + '원' + '\n' + '환율의 110% 가 되는 금액  : ' + Math.round(scwin.checkExchRt * 1.1 * 100) / 100.00 + '원' + '\n' + '\n' + (i + 1) + "번째행에 입력된 환율은 기준 환율의 " + '\n' + "90% ~ 110% 사이의 값 이어야 합니다.");
        return;
      }
    }
  }
  if (ds_evidence.isUpdated() == false) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["자료"]);
  } else {
    if (!(await scwin.f_Validation())) {
      return;
    }
    let chk = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (chk) {
      for (let i = 0; i < ds_prov.getRowCount(); i++) {
        for (let j = 0; j < ds_provHeader.getRowCount(); j++) {
          if (ds_prov.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
            ds_prov.setCellData(i, "summary", ds_provHeader.getCellData(j, "summary"));
            ds_prov.setCellData(i, "setlDt", ds_provHeader.getCellData(j, "setlDt"));
            ds_prov.setCellData(i, "bankbookNo", ds_provHeader.getCellData(j, "bankbookNo"));
            break;
          }
        }
      }
      await $c.sbm.execute($p, sbm_master);
    }
  }
};
scwin.f_Validation = async function () {
  if ((await scwin.f_ValidateEvidence()) == false) return false;
  if ((await scwin.f_ValidateAdjustment()) == false) return false;
  if ((await scwin.f_ValidateAset()) == false) return false;
  if ((await scwin.f_ValidateAreaMgnt()) == false) return false;
  let outbrCheck = 0;
  let etcCheck = 0;
  let reqAmt = 0;
  for (let i = 0; i < ds_adjustment.getRowCount(); i++) {
    if (ds_adjustment.getCellData(i, "outbrAcctCd") == "7" || ds_adjustment.getCellData(i, "outbrAcctCd") == "5") {
      outbrCheck = outbrCheck + 1;
    } else {
      reqAmt = reqAmt + Number(ds_adjustment.getCellData(i, "reqAmt"));
      etcCheck = etcCheck + 1;
    }
  }
  let row = 0;
  if (outbrCheck > 0 && etcCheck > 0) {
    if (Number(ds_evidence.getCellData(row, "spplyAmt")) + Number(ds_evidence.getCellData(row, "vat")) != reqAmt) {
      await $c.gus.cfAlertMsg($p, "공급가액과 부가세액의 합과 정산금액의 합계가 틀립니다.");
      ed_spplyAmt.setFocus();
      return false;
    }
  } else {
    let adjReqAmtSum = 0;
    for (let k = 0; k < ds_adjustment.getRowCount(); k++) {
      adjReqAmtSum += Number(ds_adjustment.getCellData(k, "reqAmt"));
    }
    if (Number(ds_evidence.getCellData(row, "spplyAmt")) + Number(ds_evidence.getCellData(row, "vat")) != adjReqAmtSum) {
      await $c.gus.cfAlertMsg($p, "공급가액과 부가세액의 합과 정산금액의 합계가 틀립니다.");
      ed_spplyAmt.setFocus();
      return false;
    }
    let acqAmtSum = 0;
    for (let k = 0; k < ds_aset.getRowCount(); k++) {
      acqAmtSum += Number(ds_aset.getCellData(k, "acqAmt"));
    }
    if (lc_deductClsCd.getValue() == scwin.NO_DEDUCT_CLS_CD) {
      if (Number(ds_evidence.getCellData(row, "spplyAmt")) + Number(ds_evidence.getCellData(row, "vat")) != acqAmtSum) {
        await $c.gus.cfAlertMsg($p, "공급가액과 부가세액의 합과 취득금액의 합계가 틀립니다.");
        ed_spplyAmt.setFocus();
        return false;
      }
    } else {
      if (Number(ed_spplyAmt.getValue()) != acqAmtSum) {
        await $c.gus.cfAlertMsg($p, "공급가액과 취득금액의 합계가 틀립니다.");
        ed_spplyAmt.setFocus();
        return false;
      }
    }
  }
  if (lc_acqCls.getValue() == "20") {
    if (lc_outbrAcctCd.getValue() != "2" && lc_outbrAcctCd.getValue() != "11") {
      if (Number(ed_reqAmt.getValue()) != Number(ed_acqAmt.getValue())) {
        await $c.win.alert($p, "금융리스 자산취득시 장기미지급금-리스부채는 공급가액과 일치해야 하고 미지급금은 부가세액과 일치해야 합니다.");
        return false;
      }
    }
    if (lc_outbrAcctCd.getValue() == "2") {
      if (Number(ed_vat.getValue()) != Number(ed_reqAmt.getValue())) {
        await $c.win.alert($p, "금융리스 자산취득시 장기미지급금-리스부채는 공급가액과 일치해야 하고 미지급금은 부가세액과 일치해야 합니다.");
        return false;
      }
    }
  }
  return true;
};
scwin.f_ValidateEvidence = async function () {
  let chk = await $c.gus.cfValidate($p, [tbl_evidence]);
  if (!chk) {
    return false;
  }
  if (ed_supplierCrn.getValue() != scwin.hid_supplierCrn) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["사업자번호"]);
    ed_supplierCrn.setFocus();
    return false;
  }
  if (ed_vatDeclarAcctDeptCd.getValue() != scwin.hid_vatDeclarAcctDeptCd) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["부가세관리부서"]);
    ed_vatDeclarAcctDeptCd.setFocus();
    return false;
  }
  return true;
};
scwin.f_ValidateAdjustment = async function () {
  if (ds_adjustment.getRowCount() < 1) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_049, ["정산내역"]);
    return false;
  }
  let chk = await $c.gus.cfValidate($p, [tbl_adjustment]);
  if (!chk) {
    return false;
  }
  if (ed_adjmAcctDeptCd.getValue().trim() != scwin.hid_adjmAcctDeptCd) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["정산귀속부서"]);
    ed_adjmAcctDeptCd.setFocus();
    return false;
  }
  if (ed_clntNo.getValue().trim() != scwin.hid_clntNo) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["정산처"]);
    ed_clntNo.setFocus();
    return false;
  }
  if (lc_outbrAcctCd.getValue() == scwin.ADJM_MTHDCD_NOPAY) {
    if (lc_reqPayMthdCd.getSelectedIndex() < 0) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["지급수단"]);
      lc_reqPayMthdCd.setFocus();
      return false;
    }
    if (!$c.gus.cfValidateValue($p, ed_payDt.getValue(), "date=YYYYMMDD")) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["지급예정일"]);
      ed_payDt.setFocus();
      return false;
    }
  }
  let adjmAmt = 0,
    adjmAmtFcrc = 0,
    prepaySum = 0,
    prepaySumFcrc = 0;
  let adjmRow = ds_adjustment.getRowPosition();
  let adjmGubun = ds_adjustment.getCellData(adjmRow, "outbrAcctCd");
  if (adjmGubun == scwin.ADJM_MTHDCD_SUSPAY) {
    adjmAmt = Number(ds_adjustment.getCellData(adjmRow, "reqAmt"));
    adjmAmtFcrc = Number(ds_adjustment.getCellData(adjmRow, "payAmtFcrc"));
    for (let j = 0; j < ds_prov.getRowCount(); j++) {
      if (ds_adjustment.getCellData(adjmRow, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
        prepaySum = prepaySum + Number(ds_prov.getCellData(j, "setlIntendAmt"));
        prepaySumFcrc = prepaySumFcrc + Number(ds_prov.getCellData(j, "setlIntendAmtFcrc"));
      }
    }
    if (prepaySum == 0 && lc_payCrcCd.getValue() == scwin.KOREA_WON) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["정리금액"]);
      return false;
    }
    if (adjmAmt != prepaySum && lc_payCrcCd.getValue() == scwin.KOREA_WON) {
      let alertMsg = (adjmGubun == scwin.ADJM_MTHDCD_PREPAY ? "선급금" : "가지급금") + " 정산금액과 정리 금액의 합계가 다릅니다.";
      await $c.gus.cfAlertMsg($p, alertMsg);
      ed_reqAmt.setFocus();
      return false;
    }
    if (prepaySumFcrc == 0 && lc_payCrcCd.getValue() != scwin.KOREA_WON) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["정리외화금액"]);
      return false;
    }
    if (adjmAmtFcrc != prepaySumFcrc && lc_payCrcCd.getValue() != scwin.KOREA_WON) {
      let alertMsg = (adjmGubun == scwin.ADJM_MTHDCD_PREPAY ? "선급금" : "가지급금") + " 정산외화금액과 정리외화 금액의 합계가 다릅니다.";
      await $c.gus.cfAlertMsg($p, alertMsg);
      ed_reqAmt.setFocus();
      return false;
    }
  }
  return true;
};
