scwin.f_CopyDataSet = function (ds_source, ds_target) {
  let currentTempAsetNo = ds_aset.getCellData(ds_aset.getRowPosition(), "tempAsetNo");
  for (let i = 0; i < ds_source.getRowCount(); i++) {
    if (ds_source.getCellData(i, "tempAsetNo") == currentTempAsetNo) {
      let newIdx = ds_target.insertRow(ds_target.getRowCount());
      let colInfos = ds_source.getColumnInfo();
      for (let c = 0; c < colInfos.length; c++) {
        let colId = colInfos[c].id;
        ds_target.setCellData(newIdx, colId, ds_source.getCellData(i, colId));
      }
    }
  }
};
