scwin.f_UndoAllValueRow = function (dataList, sColumn, columnValue) {
  if (dataList == null) return;
  if (sColumn == "") return;
  if (columnValue == "") return;
  let foundRow = scwin.f_FindValueRow(dataList, sColumn, columnValue);
  while (foundRow >= 0) {
    dataList.undoRow(foundRow);
    foundRow = scwin.f_FindValueRow(dataList, sColumn, columnValue);
  }
};
scwin.f_FindValueRow = function (dataList, sColumn, columnValue) {
  if ($c.gus.cfIsNull($p, columnValue)) return -1;
  for (let i = 0; i < dataList.getRowCount(); i++) {
    if (dataList.getCellData(i, sColumn) == columnValue) {
      return i;
    }
  }
  return -1;
};
